+
+      return { fields, step, stepKey };
+    });
+
+    return sectionsList.filter((section): section is SummarySection => section !== null);
+  }, [account, accountDocuments, addressTypes, bankAccounts, currentOnboardingSurvey, steps]);
+
+  if (summaryIsLoading) {
